import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Markdown from 'markdown-to-jsx';

import Main from '../layouts/Main';

const PostdocAd = () => {
  const [markdown, setMarkdown] = useState('');

  useEffect(() => {
    import('../data/postdoc-ad.md').then((res) => {
      fetch(res.default)
        .then((r) => r.text())
        .then(setMarkdown);
    });
  });

  return (
    <Main
      title="Postdoctoral Researcher Positions"
      description="Postdoctoral researcher positions in the Wang Lab."
    >
      <article className="post markdown" id="postdoc-ad">
        <header>
          <div className="title">
            <h2>
              <Link to="/postdoc-ad">📢 Postdoctoral Researcher Positions</Link>
            </h2>
            <p>Cardiovascular functional genomics and single-cell technologies</p>
          </div>
        </header>
        <Markdown>{markdown}</Markdown>
      </article>
    </Main>
  );
};

export default PostdocAd;
